import{c as a,Q as p,j as i,m as l}from"./chunks/framework.hhGiamYR.js";const m=JSON.parse('{"title":"致尼科洛","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/lower/170-致尼科洛.md","filePath":"research/machiavelli/machiavelli/diplomatic/lower/170-致尼科洛.md"}'),r={name:"research/machiavelli/machiavelli/diplomatic/lower/170-致尼科洛.md"};function o(t,e,c,_,n,s){return p(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="致尼科洛" tabindex="-1">致尼科洛 <a class="header-anchor" href="#致尼科洛" aria-label="Permalink to &quot;致尼科洛&quot;">​</a></h1><p>致尼科洛 · 马基雅维利 奉外务八人委员之命出访教皇圣座的司令官弗朗切斯科 ·圭恰迪尼大人 1526年11月30日</p><p>过去无论何时，我们城市和本署要派出本邦公民去执行和目前相似的 使命时，都会选择一位我们认为能够胜任的人士；把事情和办理的方式向 他口头交代过之后，若不是我们城市有一个良好的习惯，亦即提醒他注意 他所负使命的要点，我们认为没有必要再向他下达详细的训令了。所以我 们选择了你，尼科洛，因为你的能力和忠诚，现在给你这份训令，不是为 了给你一份办理章程，而是为了遵守古已有之的既定习惯，以便你总是记 得，你的使命包括以下几条主要内容，那就是：首先，你要尽可能迅速地 去和弗朗切斯科 · 圭恰迪尼先生会合，你要向他解释(尽管这似乎没什么 必要)我们城市因缺乏军队、金钱和将领而存在的混乱。尽管由于许多原 因，我们的安全措施非常薄弱，德意志雇佣兵的到来亦无济于事，你和圭 恰迪尼是知道的；但如果我们确知我们有充足的军队，以及我们寄托于他 人身上的希望不会致使我们显而易见的毁灭，那么我们还是会精神振作地 面对命运和保卫我们自己的。我们一直抱有的就是这个想法，所以直到今 天，我们才派遣弗朗切斯科 · 安东尼奥 ·诺里去见彼得罗 ·纳瓦拉伯爵， 劝他担任我们军队的指挥。假如我们确信，各同盟国和能够帮助我们的那 些人不会临阵脱逃，那么我们会进行一切可能的防御准备。但是，作为一 个共和国，尤其是像我们这样的共和国，应该考虑几个目标，仔细地权衡</p><p>出访弗朗切斯科·圭恰迪尼 每一个目标，以便知道它们的优劣，哪个不靠谱，哪个有可能成功，以便 能够选择一个危险最少的目标；所以，我们早就考虑过派你去访问司令官 阁下，因为他是我们自己的公民，忠诚地热爱着他的祖国，所以他会审视 我们的处境，根据他逐日对事情的了解说出他的想法；我们就可以知道， 根据他的判断，事情是否对我们来说毫无希望，他是否也像我们一样对我 们的安全失掉了信心。司令官阁下想必知道，我们的想法是开启谈判，以 达成某种协议，而不是放任事情发展到不可收拾的地步。 鉴于我们打算完全让他来负责此事，让他知道我们最迫切的愿望之 后，关于在他看来最好做什么的问题，你要让他自己决定。当你知道司令 官阁下是如何看待这场战争的计划、德意志雇佣兵的行为、费拉拉公爵的 武力炫耀、米兰和帕维亚的西班牙人的转移以及人们通常对这些问题的看 法；还有他是如何看待萨卢佐侯爵和威尼斯军队所带来的希望，以及同盟 和我们自己、敌人方面的所有乌合之众，搞清楚这些之后，你要立即返 回，把谈判的任务交给弗朗切斯科先生，让他相信这是我们的打算和愿 望，我们给予他全权在谈判中相机行事。</p><p>信件1</p><p>诸位大人钧鉴： 我今天一大早到了这里，随即就去拜会了司令官阁下，呈递了诸位大 人的信件，并向他详细解释了我此行的原因。司令官阁下对我说： “为了 满足你们执政团的要求，我首先要告诉您我们的部队在什么地方、敌军在 什么地方；然后，我要告诉您敌人方面需要担心什么、友军方面可以期待 什么;最后，如果我们不得不议和，那么我认为应该做些什么。德意志雇 佣兵昨天在奎斯泰洛，位于曼托瓦境内的一个地方；他们今天已渡过波 河，取道直奔里佐洛和贡扎加而去，这意味着他们打算去米兰与西班牙人 会合。据我们从多种渠道打听到的消息，这些德意志人数量大约有15000</p><p>马基雅维利全集 Opere complete di Niccolo Machiavelli</p><p>出访弗朗切斯科·圭恰迪尼 或16000,尽管我们自己的人从曼托瓦写信来说，他们的数量不超过 10000人。米兰的西班牙人仍在原地，但开始有种种迹象表明他们打算动 身离开，他们已与米兰人达成协议，米兰人付给他们30000弗罗林他们就 离开，走的正是德意志雇佣兵在走的那条路。乌尔比诺公爵率领着他带出 的所有部队出现在曼托瓦境内，与德意志人驻扎在一起，并没有表现出任 何要离开那里的迹象，尽管我已多次请求他离开。他的确派出他的一个指 挥官率领1000名步兵去皮亚琴察，他们明天就会到那里。萨卢佐侯爵在沃 雷，是贝加莫境内的一个小地方，距离米兰14英里，距离贝加莫16英里； 他的所有部队都和他在一处，共有300名以上的威尼斯重骑兵和大约1000 名步兵。乔瓦尼先生的步兵约有3000之数，将于明天入驻帕尔马。除了这 些人之外，那里还有大概4000人的部队。所以加总起来，同盟在这个地区 拥有超过20000人的兵力。 “假如教皇不让他们遭到饷银匮乏之苦，而且可以把他们集结在一 起，我们或许可以继续高枕无忧了；但是，假如他们缺少来自圣座的军 饷，他们就会变得毫无斗志，那么我们就要担心了。毫无疑问，若是所有 这些部队保持团结，而且获得丰厚的饷银，那么敌军无论按兵不动还是向 前推进，均无法取得重大的斩获，没有重大的斩获又缺乏金钱，他们将会 不战自溃。若是他们继续彼此隔离，互不协同、互不信任，那么就很难对 他们有任何指望。由于敌方已表现出想要合兵的迹象，所以在我看来，我 们会有几天太平日子来考虑要和平还是要战争；但是，当敌方的所有部队 会合之后，认为敌方会错过任何机会就不合情理了，敌军要么会进攻威尼 斯的属地，要么会进攻教会的属地，要么会入侵托斯卡纳。若是前两种情 况，你们有时间考虑你们的事务。若是第三种情况，我除了承诺给你们教 会在这里拥有的六七千人的部队之外，无法承诺给予你们其他的帮助；因 为据我对威尼斯人本性的了解，在这种情况下你们不能对他们抱有任何指 望。至于法国人，我无法说清他们是会遵从威尼斯人的建议呢，还是这种 建议会提醒他们对你们趁火打劫，因此，我对这个问题不发表任何看法，</p><p>出访弗朗切斯科·圭恰迪尼 就让事实说话吧。所以，请写信告诉你们执政团我向您说的一切，让他们 相信我会不遗余力地使我们的军队结为一体，并劝说威尼斯和罗马不要抛 弃我们，而是会做我上面对您说的事情。” 这里说到议和，司令官对我说： “在我看来议和毫无益处；因为任何 收买德意志人或与之达成协议的企图都不可能成功，因为他们与西班牙人 会组成同一个军团。因此，和平谈判需要与获得皇帝授权的人展开，而我 认为波旁元帅①或这边的任何其他指挥官都没有获得这种授权；但我认为 你们那边的总督[或]唐胡果②获得了这种授权，因为我们听说总督带领他 的一部分舰队已在锡耶纳所属的港口圣斯特凡诺登陆。所以，和平谈判最 好在佛罗伦萨启动；我认为教皇已着手进行这件事了，这似乎会有一个好 的结果。简言之，我们看到这边的这些动向会给我们时间思考补救措施， 无论是以和平还是其他的手段来补救，对您而言，最好让你们执政团明白 这一点。” 这就是我能够从司令官阁下那里打听到的消息的大意，我认为最好以 这些文字告知你们，使诸位大人可以明了事情的全部面目。我会在这里继 续待几天，看看有没有什么特别的事情发生，这样我回来时，会对这里的 事态有更充分的了解。 敬请诸位大人多多关照。再会。</p><p>1526年12月2日 诸位大人想必已听闻乔瓦尼大人③之死，他的死值得所有人哀悼。</p><p>仆尼科洛 · 马基雅维利，摩德纳</p><p>①查理三世 · 德 · 波旁( Charles II de Bourbon,1490-1527)原为法国统帅，1523年叛投皇帝查理五 世。 ——中译者注 ②那不勒斯总督查理 · 德 · 拉努瓦( Charles de Lannoy)或唐胡果 · 德 · 蒙卡达( don Hugo de Moncada)。——贝尔泰利编校本注 ③乔瓦尼 ·德 ·梅迪奇，即“黑条”乔瓦尼，他死于1526年11月24日。他是卡泰丽娜 ·斯福尔扎和乔瓦 尼 · 德 · 梅迪奇(“平民”乔瓦尼)的儿子。 — — 英译本注</p><p>出访弗朗切斯科·主恰迪尼</p><p>诸位大人钧鉴： 在昨天的信里，我详细报告了我从司令官处打听到的有关这里的情 况，现在没有任何重要的事情需要补充，只是简短地重复同样的内容，那 就是：假如敌人从你们那方来，你们将可以得到教会在这里的军队的帮 助，数量大约是7000名步兵。但是，你们不可把希望全部押在这些士兵 身上，因为他们中的一部分将不得不离开这里。或许你们能够使用法国的 军队，但司令官对此表示十分怀疑。至于威尼斯人，看来十分肯定的是， 他们希望留在国内。关于你们目前能够雇用的指挥官和他们的部队，诸位 大人必须明白，这里你们能够倚重的重要人物只有3个，他们是：圭多伯 爵①、曼托瓦军队的指挥官保罗 ·卢扎斯科，以及圭多 · 瓦伊纳；在这3位 阁下中你们可以选择最适合你们的1位。我们今天通过多种渠道获悉，德 意志雇佣兵驻扎在瓦斯托拉和贝尔塞利之间，因此他们既能向皮亚琴察转 移，也能向帕尔马转移；关于这一点，我们尽管没有官方的消息，但许多 消息来源都这样说，因此我们相信是真的。</p>',14)])])}const h=a(r,[["render",o]]);export{m as __pageData,h as default};
